function sourceSignature() {
  const hash = createHash('sha256');
  for (const sourcePath of SOURCE_PATHS) {
    try {
      const stat = statSync(sourcePath);
      hash.update(sourcePath);
      hash.update('\u001f');
      hash.update(String(stat.mtimeMs));
